        // We need to select 'l_visible' from the left side and 'r_visible' from the right side
        // such that l_visible + r_visible = k.

        long totalWaysForK = 0;

        // Iterate over the number of visible people from the left side (l_visible)
        // l_visible can range from max(0, k - rightCount) to min(k, leftCount)

