            // The remaining (rightCount - r_visible) must choose 'L'.
            // Ways_R = C(rightCount, r_visible)
            long waysR = combinations(rightCount, r_visible);

            // Total ways for this specific split (l_visible, r_visible)
            long waysSplit = (waysL * waysR) % MOD;

            totalWaysForK = (totalWaysForK + waysSplit) % MOD;
        }

        // The total answer is (Ways to achieve K) * (Options for pos)
        long finalAnswer = (totalWaysForK * posOptions) % MOD;

        return finalAnswer;
    }
